-- Bulk import of 4,468 SA wards from MDB ArcGIS Feature Service
-- Existing wards keep their demographic data (ON CONFLICT DO UPDATE only coordinates/names)

ON CONFLICT (ward_code) DO UPDATE SET
  municipality = EXCLUDED.municipality,
  centroid_lat = COALESCE(ward_demographics.centroid_lat, EXCLUDED.centroid_lat),
  centroid_lng = COALESCE(ward_demographics.centroid_lng, EXCLUDED.centroid_lng);

